            int N = sc.nextInt();
            int P = sc.nextInt();
            long count = 0;
            for (int i = 111; i <= P; i++) {
                for (int j = 111; j <= P; j++) {
                    for (int k = 111; k <= P; k++) {
                        int score = (((N % i) % j) % k) % N;
                        if (score == N - 1) {
